```javascript
function findObjectByPath(obj, path) {
  let currentObj = obj;
  let currentPath = '';

  while (currentObj && currentPath !== path) {
    for (let key in currentObj) {
      if (key === path) {
        return { object: currentObj, path: currentPath };
      }

      if (typeof currentObj[key] === 'object') {
        currentObj = currentObj[key];
        currentPath += `${key}/`;
      }
