Here is an example of blocking read interrupted by signal, with EINTR handling:

```c
#include <stdio.h>
#include <stdlib.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int status;
    pid_t pid;

    pid = fork();
    if (pid == 0) {
        // Child process
        printf("Child process started.\n");
        sleep(10);
        printf("Child process finished.\n");
        exit(0);
    } else {
        // Parent process
        printf("Parent process started.\n");
        sleep(5);
        printf("Parent process sending signal to child process.\n");
        kill(pid, SIGINT);
        printf("Parent process waiting for child process to finish.\n");
        waitpid(pid, &status, 0);
        printf("Child process finished with status %d.\n", status);
        exit(0);
    }
    return 0;
}
```

In this example, the parent process creates a child process using the `fork()` function. The child process sleeps for 10 seconds and then exits. The parent process sleeps for 5 seconds and then sends a signal to the child process using the `kill()` function. The parent process then waits for the child process to finish using the `waitpid()` function. The parent process then prints the status of the child process.

Here is an example C++ code to read network packets from a socket on port 888:

```c++
#include <iostream>
#include <sys/types.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>

int main() {
    int socket_fd;
    struct sockaddr_in server_address;

    // Create a socket
    socket_fd = socket(AF_INET, SOCK_STREAM, 0);

    // Set up the server address
    server_address.sin_family = AF_INET;
    server_address.sin_port = htons(888);
    server_address.sin_addr.s_addr = INADDR_ANY;

    // Bind the socket to the server address
    if (bind(socket_fd, (struct sockaddr *)&server_address, sizeof(server_address)) < 0) {
        std::cerr << "Error: Failed to bind socket to server address." << std::endl;
        return 1;
    }

    // Listen for incoming connections
    if (listen(socket_fd, 5) < 0) {
        std::cerr << "Error: Failed to listen for incoming connections." << std::endl;
        return 1;
    }

    // Accept an incoming connection
    struct sockaddr_in client_address;
    socklen_t client_address_length = sizeof(client_address);

    int client_socket_fd = accept(socket_fd, (struct sockaddr *)&client_address, &client_address_length);

    if (client_socket_fd < 0) {
        std::cerr << "Error: Failed to accept an incoming connection." << std::endl;
        return 1;
    }

    // Read data from the client socket
    char buffer[1024];
    int bytes_read = read(client_socket_fd, buffer, 1024);

    if (bytes_read < 0) {
        std::cerr << "Error: Failed to read data from client socket." << std::endl;
        return 1;
    }

    // Print the data received from the client socket
    std::cout << "Received " << bytes_read << " bytes from client socket: " << std::string(buffer, bytes_read) << std::endl;

    // Close the client socket
    close(client_socket_fd);

    // Close the server socket
    close(socket_fd);

    return 0;
}
```

This code creates a socket on port 888, listens for incoming connections, accepts an incoming connection, reads data from the client socket, prints the data received from the client socket, closes the client socket, and closes the server socket.

