```python
import random

# roll result enum
class fail():
    def __repr__(self):
        return "fail"
fail = fail()

class partial():
    def __repr__(self):
        return "partial"
partial = partial()

class success():
    def __repr__(self):
        return "success"
success = success()

class critical():
    def __repr__(self):
        return "critical"
critical = critical()


def roll(n):
    """roll nd6 and return a list of rolls"""
    return [random.randint(1, 6) for _ in range(n)]


def determine_result(rolls):
    """determine the result based on the rolls"""
    if rolls.count(6) >= 3:
        return critical
    if 6 in rolls:
        return success
    if rolls.count(5) >= 3:
        return success
    if 5 in rolls:
        return partial
    if 4 in rolls:
        return fail
    return fail


def make_roll(skill=0, stat=0, difficulty=0, help=False, bargain=False):
    """make a roll with the given skill, stat, and difficulty"""
    rolls = roll(skill + stat + difficulty + (1 if help else 0) + (1 if bargain else 0)
    result = determine_result(rolls)
    return rolls, result
```

