To ensure that the memory region is mapped, you can use the `vmalloc` function provided by the Linux kernel. This function allocates memory from the kernel's virtual memory area, which is mapped into the process's address space.

Here's an example of how to use `vmalloc` to allocate memory at the desired virtual address:

```c
#include <linux/module.h>
#include <linux/slab.h>

#define MEM_SIZE 4096

static void *mem;

static int __init my_module_init(void)
{
    mem = vmalloc(MEM_SIZE);
    if (!mem) {
        pr_err("Failed to allocate memory\n");
        return -ENOMEM;
    }
    pr_info("Memory allocated at %p\n", mem);
    return 0;
}

static void __exit my_module_exit(void)
{
