        CheckingAccountTypeStrategy checkingAccountTypeStrategy = new CheckingAccountTypeStrategy();
        SavingsAccountTypeStrategy savingsAccountTypeStrategy = new SavingsAccountTypeStrategy();

        BankingAppSystem bankingAppSystemChecking = new BankingAppSystem(checkingAccountTypeStrategy);
        BankingAppSystem bankingAppSystemSavings = new BankingAppSystem(savingsAccountTypeStrategy);

