Here's a Python click script that removes silence from voice recordings:

```python
import os
import sys

import librosa
import numpy as np

from click import command, argument, echo


@command()
@argument('input_file', type=str, required=True)
@argument('output_file', type=str, required=False)
def remove_silence(input_file, output_file=None):
    """
    Remove silence from a voice recording.

    :param input_file: The input file path.
    :param output_file: The output file path (optional).
    :return: None
    """
    # Set the output file path if it's not specified.
    if output_file is None:
        output_file = os.path.splitext(input_file)[0] + '_no_silence' + os.path.splitext(input_file)[1]

    # Load the input file.
    try:
        audio, sample_rate = librosa.load(input_file, sr=None)
    except FileNotFoundError:
        echo(f"Error: Input file '{input_file}' not found.")
        sys.exit(1)

    # Remove silence from the audio.
    audio = librosa.effects.trim(audio, top_db=20)[0]

    # Save the output file.
    try:
        librosa.output.write_wav(output_file, audio, sample_rate)
    except Exception as e:
        echo(f"Error: Could not save output file '{output_file}'. Error: {e}")
        sys.exit(1)

    echo(f"Output file '{output_file}' saved successfully.")
```

