def check_winner(board):
    # check rows
    for row in board:
        if all(cell == 'x' for cell in row):
            return 'x'
        elif all(cell == 'o' for cell in row):
            return 'o'
    # check columns
    for col in range(7):
        cells = [board[row][col] for row in range(6)]
        if all(cell == 'x' for cell in cells):
            return 'x'
        elif all(cell == 'o' for cell in cells):
            return 'o'
    # check diagonals
    for row in range(3):
        for col in range(4):
            cells = [board[row + i][col + i] for I in range(3)]
            if all(cell == 'x' for cell in cells):
                return 'x'
            elif all(cell == 'o' for cell in cells):
                return 'o'
    return None

def check_valid_move(board, col):
    if col < 0 or col > 6:
        return False
    for row in range(6, -1, -1):
        if board[row][col] == ' ':
            return True
    return False

def make_move(board, col, player):
    if not check_valid_move(board, col):
        return False
    for row in range(6, -1, -1):
        if board[row][col] == ' ':
            board[row][col] = player
            return True
    return False

def switch_player(player):
    if player == 'x':
        return 'o'
    elif player == 'o':
        return 'x'
    else:
        return None

def display_board(board):
    print('   1   2   3   4   5   6')
    for row in range(6):
        print(row + 1, end=' ')
        for col in range(7):
            print(board[row][col], end=' ')
        print()
    print()

def start_game():
    board = [[' ' for I in range(7)] for j in range(6)]
    player = 'x'
    while True:
        display_board(board)
        col = int(input('Enter column (1-7): '))
        if not check_valid_move(board, col, player):
            print('Invalid move. Please try again.')
            continue
        if not make_move(board, col, player):
            print('Invalid move. Please try again.')
            continue
        if check_winner(board, player):
            display_board(board)
            print(f'Player {player} wins!')
            return
        player = switch_player(player)
    print('The game is a tie.')

def main():
    start_game()

if __name__ == '__main__':
    main()
```

This program will start the game and display the board, prompt the user for a column to drop a piece, check if the move is valid, make the move, check if a player has won, and display the board again. The program will continue to run until a player has won or the game is a tie.

